// --- Academic Year Rollover Functions ---
function toggleSyncModeUI() {
    const isDemo = document.getElementById('sync-mode-demo').checked;
    const demoDesc = document.getElementById('demo-mode-desc');
    const prodDesc = document.getElementById('prod-mode-desc');

    if (isDemo) {
        if (demoDesc) demoDesc.style.display = 'block';
        if (prodDesc) prodDesc.style.display = 'none';
        document.getElementById('sync-mode-demo').parentElement.style.color = 'var(--primary-dark)';
        document.getElementById('sync-mode-prod').parentElement.style.color = 'var(--text-muted)';
    } else {
        if (demoDesc) demoDesc.style.display = 'none';
        if (prodDesc) prodDesc.style.display = 'block';
        document.getElementById('sync-mode-demo').parentElement.style.color = 'var(--text-muted)';
        document.getElementById('sync-mode-prod').parentElement.style.color = 'var(--primary-dark)';
    }
}

function renderRetainedStudentsList() {
    const container = document.getElementById('retained-list-container');
    if (!container) return;

    let html = '';
    const classes = ['m3', 'm2', 'm1'];
    const classLabels = { 'm3': 'ม.3', 'm2': 'ม.2', 'm1': 'ม.1' };

    classes.forEach(cls => {
        const rooms = ['1', '2', '3'];
        rooms.forEach(rm => {
            const roster = studentRosters[cls]?.[rm] || [];
            roster.forEach(student => {
                html += `
                    <label style="display: flex; align-items: center; justify-content: space-between; padding: 6px 10px; background: var(--secondary); border-radius: 6px; border: 1px solid var(--border); cursor: pointer; transition: all 0.2s; user-select: none;">
                        <div style="display: flex; align-items: center; gap: 8px;">
                            <input type="checkbox" class="retained-checkbox" value="${student.id}" style="cursor: pointer;">
                            <span style="font-weight: 500; color: var(--text-main);">${student.name}</span>
                        </div>
                        <span style="font-size: 0.72rem; background: var(--white); padding: 2px 6px; border-radius: 10px; border: 1px solid var(--border); font-weight: 600; color: var(--primary-dark);">${classLabels[cls]}/${rm}</span>
                    </label>
                `;
            });
        });
    });

    container.innerHTML = html || '<div style="color: var(--text-muted); text-align: center; padding: 10px;">ไม่มีข้อมูลรายชื่อนักเรียน</div>';
}

function triggerRolloverProcess() {
    const isDemo = document.getElementById('sync-mode-demo').checked;
    const modeText = isDemo ? "จำลองระบบ (Demo Mode - LocalStorage)" : "เซิร์ฟเวอร์จริง (Production Mode - API Server)";

    const conf = confirm(`⚠️ คุณต้องการดำเนินการเลื่อนชั้นปีการศึกษาของนักเรียนใช่หรือไม่?\n\nโหมดที่เลือก: ${modeText}\n\n* ข้อมูลประวัติเช็คชื่อปีปัจจุบันจะถูก Backup เก็บถาวร\n* นักเรียน ม.3 จะจบการศึกษา (ยกเว้นคนซ้ำชั้น)\n* นักเรียน ม.1, ม.2 จะถูกเลื่อนชั้นขึ้น 1 ระดับชั้น\n\nกด OK เพื่อยืนยันและรันคำสั่ง`);
    if (!conf) return;

    const promptVal = prompt("โปรดพิมพ์คำว่า CONFIRM เพื่อยืนยันการทำรายการเลื่อนชั้นปี:");
    if (promptVal !== "CONFIRM") {
        alert("คำยืนยันไม่ถูกต้อง ระบบยกเลิกการทำงาน");
        return;
    }

    runRolloverProcess();
}

function runRolloverProcess() {
    const isDemo = document.getElementById('sync-mode-demo').checked;

    // Get retained student IDs
    const checkboxes = document.querySelectorAll('.retained-checkbox');
    const retainedIds = new Set();
    checkboxes.forEach(cb => {
        if (cb.checked) {
            retainedIds.add(cb.value);
        }
    });

    if (isDemo) {
        try {
            // 1. Archive attendance history
            const currentHistory = localStorage.getItem('lms-attendance-history') || '[]';
            localStorage.setItem('lms-attendance-history-archived', currentHistory);

            // 2. Archive student rosters
            localStorage.setItem('lms-student-rosters-archived', JSON.stringify(studentRosters));

            // 3. Clear today's attendance in history (for new year starting fresh)
            localStorage.setItem('lms-attendance-history', '[]'); 

            // 4. Update studentRosters in localStorage
            const newRosters = {
                'm3': { '1': [], '2': [], '3': [] },
                'm2': { '1': [], '2': [], '3': [] },
                'm1': { '1': [], '2': [], '3': [] }
            };

            const graduates = [];
            const classes = ['m3', 'm2', 'm1'];

            classes.forEach(cls => {
                const rooms = ['1', '2', '3'];
                rooms.forEach(rm => {
                    const roster = studentRosters[cls]?.[rm] || [];
                    roster.forEach(student => {
                        const isRetained = retainedIds.has(student.id);
                        if (cls === 'm3') {
                            if (isRetained) {
                                newRosters['m3'][rm].push(student);
                            } else {
                                graduates.push(student);
                            }
                        } else if (cls === 'm2') {
                            if (isRetained) {
                                newRosters['m2'][rm].push(student);
                            } else {
                                newRosters['m3'][rm].push(student);
                            }
                        } else if (cls === 'm1') {
                            if (isRetained) {
                                newRosters['m1'][rm].push(student);
                            } else {
                                newRosters['m2'][rm].push(student);
                            }
                        }
                    });
                });
            });

            // Populate new mock students for M.1
            newRosters['m1']['1'] = [
                { id: 'stu-m1-new-1', name: 'จักรินทร์ ใจรัก', email: 'student.jak@lms.ac.th', code: '690101', avatar: 'จ', loginTime: 'ยังไม่เข้าสู่ระบบ' },
                { id: 'stu-m1-new-2', name: 'ขวัญชนก ดีเลิศ', email: 'student.kwan@lms.ac.th', code: '690102', avatar: 'ข', loginTime: 'ยังไม่เข้าสู่ระบบ' }
            ];
            newRosters['m1']['2'] = [
                { id: 'stu-m1-new-3', name: 'ธนากร รักดี', email: 'student.thana@lms.ac.th', code: '690201', avatar: 'ธ', loginTime: 'ยังไม่เข้าสู่ระบบ' },
                { id: 'stu-m1-new-4', name: 'กนกวรรณ รุ่งเรือง', email: 'student.kanok@lms.ac.th', code: '690202', avatar: 'ก', loginTime: 'ยังไม่เข้าสู่ระบบ' }
            ];
            newRosters['m1']['3'] = [
                { id: 'stu-m1-new-5', name: 'ศิริชัย เรียนเก่ง', email: 'student.siri@lms.ac.th', code: '690301', avatar: 'ศ', loginTime: 'ยังไม่เข้าสู่ระบบ' }
            ];

            studentRosters = newRosters;
            localStorage.setItem('lms-student-rosters', JSON.stringify(studentRosters));

            // 5. Update leaderboardDatabase
            leaderboardDatabase.forEach(item => {
                let found = false;
                for (let cls of ['m3', 'm2', 'm1']) {
                    for (let rm of ['1', '2', '3']) {
                        const match = newRosters[cls][rm].find(s => s.name === item.name);
                        if (match) {
                            item.class = cls;
                            item.room = `ม.${cls === 'm3' ? '3' : cls === 'm2' ? '2' : '1'}/${rm}`;
                            found = true;
                            break;
                        }
                    }
                    if (found) break;
                }

                if (!found) {
                    const isGrad = graduates.find(s => s.name === item.name);
                    if (isGrad) {
                        item.class = 'graduated';
                        item.room = 'จบการศึกษา';
                    }
                }
            });

            localStorage.setItem('lms-leaderboard-database', JSON.stringify(leaderboardDatabase));

            // Broadcast message
            bc.postMessage({
                type: 'ACADEMIC_ROLLOVER_SUCCESS',
                year: 2570,
                graduatesCount: graduates.length
            });

            showToast('สำเร็จ', 'จำลองการเลื่อนระดับชั้นปีการศึกษา 2570 สำเร็จ! ย้ายสถิติและขยับนักเรียนแล้ว', 'success');

            // Refresh UI
            renderRetainedStudentsList();
            if (typeof renderStudentList === 'function') renderStudentList();
            if (typeof updateClassLeaderboardUI === 'function') updateClassLeaderboardUI();
        } catch (err) {
            showToast('ข้อผิดพลาด', 'เกิดข้อผิดพลาดในการประมวลผล LocalStorage: ' + err.message, 'danger');
        }
    } else {
        // --- PRODUCTION MODE (API Server) ---
        showToast('API Request', 'ระบบส่งคำขอด่วนเพื่อรัน Database Transaction: POST /api/admin/rollover...', 'info');

        setTimeout(() => {
            showToast('สำเร็จ (เซิร์ฟเวอร์)', 'หลังบ้านประมวลผลสำเร็จและตอบกลับสถานะ 200 OK (รัน pg_dump + Prisma Transaction เรียบร้อย)', 'success');
        }, 1500);
    }
}

